<template><div class="min-h-screen flex flex-col bg-[#FFF9F9] text-rose-950 font-sans selection:bg-rose-200 overflow-hidden relative px-4"><div class="fixed inset-0 pointer-events-none"><div class="absolute -top-20 -left-20 w-80 h-80 bg-rose-200/40 rounded-full blur-[100px] animate-pulse"></div><div class="absolute top-1/3 -right-20 w-96 h-96 bg-orange-100/30 rounded-full blur-[120px]"></div></div><header class="relative z-10 pt-10 pb-6 text-center"><div class="inline-flex items-center gap-2 px-3 py-1 bg-white/40 backdrop-blur-md rounded-full border border-white/50 mb-4 shadow-sm"><span class="flex h-2 w-2 rounded-full bg-rose-400 animate-ping"></span><span class="text-[10px] font-black tracking-widest text-rose-500 uppercase">Star Scout AI</span></div><h1 class="text-3xl font-black bg-gradient-to-b from-rose-500 to-rose-700 bg-clip-text text-transparent">猫咪颜值大赏</h1><p class="text-xs text-rose-400 mt-2 font-medium">测测主子的出道潜力 ✨</p></header><main class="relative z-10 flex-1 max-w-md mx-auto w-full"><section v-if="step==='home'" class="space-y-10 animate-in fade-in slide-in-from-bottom-8 duration-1000"><div class="bg-white/40 backdrop-blur-2xl rounded-[2.5rem] p-8 shadow-2xl border border-white/60 text-center"><label class="block text-[10px] font-black text-rose-300 mb-6 uppercase tracking-widest">Step 1: 主子品种 Breed</label><div class="grid grid-cols-2 gap-3"><button v-for="b in breeds" :key="b" @click="breed=b" :class="breed===b?'bg-rose-500 text-white shadow-lg shadow-rose-200 scale-105':'bg-white/60 text-rose-400'" class="flex items-center justify-center gap-2 py-4 px-2 rounded-2xl font-bold text-xs transition-all border border-white/40"><span>{{ b==='自动识别'?'🔍':b==='布偶猫'?'👸':b==='英国短毛猫'?'🐱':b==='美国短毛猫'?'🐾':'✨' }}</span>{{ b }}</button></div></div><div class="space-y-4"><button @click="openCamera" class="w-full py-6 rounded-3xl bg-rose-500 text-white font-black shadow-lg shadow-rose-200 active:scale-95 transition-all flex items-center justify-center gap-3 relative overflow-hidden group"><span class="text-2xl">📸</span><span class="tracking-widest font-black uppercase">立即试镜 Debut</span></button><input ref="fileInput" type="file" accept="image/*" class="hidden" @change="onFileSelected"/><button @click="openAlbum" class="w-full py-6 rounded-3xl bg-white/60 backdrop-blur-md border border-white text-rose-400 font-bold active:scale-95 transition-all flex items-center justify-center gap-3 shadow-sm"><span class="text-xl">🎞️</span><span class="tracking-widest font-black uppercase">从相册选</span></button></div></section><section v-if="step==='loading'" class="flex flex-col items-center justify-center py-32"><div class="relative w-32 h-32"><div class="absolute inset-0 rounded-full border-[10px] border-white shadow-lg"></div><div class="absolute inset-0 rounded-full border-[10px] border-t-rose-400 animate-spin"></div><div class="absolute inset-0 flex items-center justify-center text-3xl animate-bounce">💖</div></div><div class="mt-12 text-center"><h3 class="text-xl font-black text-rose-500 mb-2">{{ loadingText }}</h3><p class="text-[10px] text-rose-300 font-bold uppercase tracking-widest">金牌经纪人正在火速评估...</p></div></section><section v-if="step==='result'&&result" class="space-y-8 animate-in fade-in slide-in-from-bottom-12 duration-1000 pb-20"><div class="bg-white/60 backdrop-blur-3xl rounded-[3.5rem] shadow-2xl border border-white overflow-hidden pb-10 px-6 text-center"><div class="p-10 text-center relative overflow-hidden"><div class="inline-block px-4 py-1.5 rounded-full bg-rose-500 text-white text-[10px] font-black uppercase mb-4 shadow-lg">Talent Report</div><div class="text-sm font-black text-rose-300 uppercase tracking-[0.3em] mb-2">{{ result.star_potential }}</div><h2 class="text-4xl font-black text-rose-600 mb-4 tracking-tighter">{{ result.cat_title }}</h2><p class="text-xs font-bold text-rose-400 italic mb-8">" {{ result.inner_monologue }} "</p><div class="relative inline-flex mb-8"><svg class="w-40 h-40 transform -rotate-90 relative"><circle cx="80" cy="80" r="72" stroke="currentColor" stroke-width="12" fill="transparent" class="text-white/80"/><circle cx="80" cy="80" r="72" stroke="currentColor" stroke-width="12" fill="transparent" class="text-rose-400 transition-all duration-1500" :style="{strokeDasharray:452.4,strokeDashoffset:452.4*(1-result.total_score/100)}"/></svg><div class="absolute inset-0 flex flex-col items-center justify-center"><span class="text-5xl font-black text-rose-500 tracking-tighter">{{ result.total_score }}</span><span class="text-[11px] font-black text-rose-300 uppercase">颜值分</span></div></div></div><div class="space-y-6 px-2"><div class="bg-rose-500 p-6 rounded-[2rem] text-white shadow-xl text-left"><span class="text-[10px] font-black text-rose-100/80 uppercase block mb-1">性格测算 Personality</span><p class="text-base font-bold leading-relaxed">{{ result.personality }}</p></div><div class="grid grid-cols-1 gap-4"><div v-for="(content, key) in result.detailed_analysis" :key="key" class="bg-white/40 p-5 rounded-3xl border border-white/60 text-left text-xs font-bold"><span class="text-[9px] font-black text-rose-300 uppercase block mb-1">{{ key }} Spotlight</span>{{ content }}</div></div><div class="bg-rose-50/60 p-6 rounded-[2rem] border border-white text-center text-sm text-rose-800 font-bold italic leading-relaxed">"{{ result.expert_advice }}"</div></div></div><div class="grid grid-cols-2 gap-4"><button @click="generatePoster" class="py-5 rounded-4xl bg-rose-500 text-white font-black shadow-lg shadow-rose-200 active:scale-95 transition-all text-xs tracking-widest uppercase disabled:opacity-50" :disabled="isGenerating">{{ isGenerating ? '生成中...' : '生成出道海报' }}</button><button @click="reset" class="py-5 rounded-4xl bg-rose-100 text-rose-500 font-black mb-8 tracking-widest uppercase text-xs active:scale-95 transition-all">再推一个主子</button></div></section></main><div id="poster-container" v-if="result" class="fixed top-0 left-0 -z-50 opacity-0 pointer-events-none w-[375px] bg-[#FFF9F9] p-8 font-sans text-rose-950"><div class="relative rounded-[3rem] overflow-hidden bg-white shadow-2xl border-[12px] border-white"><img :src="localImageUrl" class="w-full h-[400px] object-cover" @load="imageLoaded = true"/><div class="p-8 text-center"><div class="text-[10px] font-black tracking-[0.3em] text-rose-300 uppercase mb-4">Talent Discovery Report</div><div class="text-sm font-black text-rose-400 mb-1 uppercase tracking-widest">{{ result.star_potential }}</div><h2 class="text-4xl font-black text-rose-600 mb-4 tracking-tighter">{{ result.cat_title }}</h2><div class="flex justify-center items-baseline gap-1 mb-6 text-rose-500 font-black"><span class="text-5xl tracking-tighter">{{ result.total_score }}</span><span class="text-xs uppercase">颜值分</span></div><p class="text-sm font-bold text-rose-800 italic bg-rose-50/50 p-4 rounded-2xl mb-6 leading-relaxed">" {{ result.inner_monologue }} "</p><div class="text-left bg-rose-500 p-5 rounded-3xl text-white shadow-lg"><span class="text-[9px] font-black opacity-80 uppercase block mb-1">性格画像 Personality</span><p class="text-xs font-bold leading-relaxed">{{ result.personality }}</p></div><div class="mt-8 pt-6 border-t border-rose-100 opacity-30 text-[9px] font-black tracking-[0.4em] uppercase text-rose-500 text-center">AI Star Scout · Pro Edition</div></div></div></div></div></template><script setup>import {ref,computed,nextTick} from 'vue';import {compressImage} from './utils/compress.js';import {toPng} from 'html-to-image';const breeds=['自动识别','布偶猫','英国短毛猫','美国短毛猫','其他'],breed=ref('自动识别'),step=ref('home'),result=ref(null),uploading=ref(false),isGenerating=ref(false),fileInput=ref(null),localImageUrl=ref(''),imageLoaded=ref(false),loadingTexts=['正在挖掘星味...','正在测算性格...','正在脑补独白...','正在撰写出道建议...','主子即将惊艳登场...'],loadingTextIndex=ref(0);let loadingInterval=null;const loadingText=computed(()=>loadingTexts[loadingTextIndex.value]);function startLoadingAnimation(){loadingTextIndex.value=0;loadingInterval=setInterval(()=>{if(loadingTextIndex.value<loadingTexts.length-1)loadingTextIndex.value++},2500)}function stopLoadingAnimation(){if(loadingInterval){clearInterval(loadingInterval);loadingInterval=null}}function getApiBase(){return import.meta.env.DEV?'':(import.meta.env.VITE_API_BASE||'')}async function uploadAndEvaluate(blob){step.value='loading';startLoadingAnimation();uploading.value=true;result.value=null;try{const form=new FormData();form.append('file',blob,'cat.jpg');form.append('breed',breed.value);const res=await fetch(`${getApiBase()}/api/evaluate`,{method:'POST',body:form,signal:AbortSignal.timeout(120000)});if(!res.ok){const err=await res.json().catch(()=>({}));throw new Error(err.detail||res.statusText||'请求失败')}result.value=await res.json();step.value='result'}catch(e){alert('试镜失败：'+(e.message||String(e)));step.value='home'}finally{uploading.value=false;stopLoadingAnimation()}}function openCamera(){if(!fileInput.value)return;fileInput.value.setAttribute('capture','environment');fileInput.value.click()}function openAlbum(){if(!fileInput.value)return;fileInput.value.removeAttribute('capture');fileInput.value.click()}async function onFileSelected(ev){const file=ev.target.files?.[0];if(!file)return;ev.target.value='';try{localImageUrl.value=URL.createObjectURL(file);imageLoaded.value=false;const blob=await compressImage(file,1200,0.82);await uploadAndEvaluate(blob)}catch(e){alert('处理失败：'+String(e))}}function reset(){step.value='home';result.value=null;localImageUrl.value='';imageLoaded.value=false}async function generatePoster(){if(isGenerating.value)return;isGenerating.value=true;const el=document.getElementById('poster-container');if(!el)return;try{await nextTick();await new Promise(r=>setTimeout(r,500));await toPng(el);const dataUrl=await toPng(el,{quality:1,backgroundColor:'#FFF9F9',pixelRatio:2});const link=document.createElement('a');link.download=`猫咪出道海报-${result.value.cat_title}.png`;link.href=dataUrl;link.click()}catch(e){alert('生成失败，请重试')}finally{isGenerating.value=false}}</script><style>@import url('https://fonts.googleapis.com/css2?family=Noto+Sans+SC:wght@400;700;900&display=swap');body{-webkit-tap-highlight-color:transparent;background:#FFF9F9;font-family:'Noto Sans SC',sans-serif}::-webkit-scrollbar{display:none}.rounded-4xl{border-radius:2rem}</style>
